import{_ as d,o as a,c as r,ag as l}from"./chunks/framework.Vng7Hdlh.js";const u=JSON.parse('{"title":"6. 注文管理（ハンディPOS）","description":"","frontmatter":{},"headers":[],"relativePath":"tenant/06-orders.md","filePath":"tenant/06-orders.md"}'),e={name:"tenant/06-orders.md"};function i(h,t,o,n,s,b){return a(),r("div",null,[...t[0]||(t[0]=[l('<h1 id="_6-注文管理-ハンディpos" tabindex="-1">6. 注文管理（ハンディPOS） <a class="header-anchor" href="#_6-注文管理-ハンディpos" aria-label="Permalink to &quot;6. 注文管理（ハンディPOS）&quot;">​</a></h1><p>ハンディPOS（<code>/handy/</code>）は、スタッフがスマートフォンやタブレットから注文を入力するための画面です。店内飲食の注文とテイクアウトの注文の両方に対応しています。全てのロール（スタッフ・マネージャー・オーナー）で利用できます。</p><p>管理ダッシュボードのヘッダーにある「ハンディ」リンクをクリックすると、新しいタブで開きます。</p><h2 id="_6-1-画面構成" tabindex="-1">6.1 画面構成 <a class="header-anchor" href="#_6-1-画面構成" aria-label="Permalink to &quot;6.1 画面構成&quot;">​</a></h2><h3 id="ヘッダー" tabindex="-1">ヘッダー <a class="header-anchor" href="#ヘッダー" aria-label="Permalink to &quot;ヘッダー&quot;">​</a></h3><table tabindex="0"><thead><tr><th>位置</th><th>要素</th><th>説明</th></tr></thead><tbody><tr><td>左</td><td>タイトル「ハンディ」</td><td>—</td></tr><tr><td>右</td><td>店舗名</td><td>現在操作中の店舗名</td></tr><tr><td>右</td><td>店舗切替リンク</td><td>複数店舗に所属している場合のみ表示</td></tr><tr><td>右</td><td>ユーザー名</td><td>ログイン中のスタッフ名</td></tr><tr><td>右</td><td>ログアウトボタン</td><td>—</td></tr></tbody></table><h3 id="メインタブ-4つ" tabindex="-1">メインタブ（4つ） <a class="header-anchor" href="#メインタブ-4つ" aria-label="Permalink to &quot;メインタブ（4つ）&quot;">​</a></h3><table tabindex="0"><thead><tr><th>タブ名</th><th>説明</th></tr></thead><tbody><tr><td>店内注文</td><td>店内飲食の注文入力（デフォルト）</td></tr><tr><td>テイクアウト</td><td>テイクアウト注文の入力</td></tr><tr><td>テーブル状況</td><td>テーブルの着席・メモ・ステータス管理</td></tr><tr><td>注文履歴</td><td>当日の注文一覧と編集</td></tr></tbody></table><h3 id="店舗選択" tabindex="-1">店舗選択 <a class="header-anchor" href="#店舗選択" aria-label="Permalink to &quot;店舗選択&quot;">​</a></h3><p>複数店舗に所属しているスタッフの場合、初回アクセス時に店舗選択オーバーレイが表示されます。</p><ol><li>所属店舗の一覧が表示されます</li><li>操作する店舗をタップします</li><li>選択した店舗はブラウザに記憶されます（localStorage）</li><li>次回アクセス時は同じ店舗が自動選択されます</li></ol><hr><h2 id="_6-2-店内注文の流れ" tabindex="-1">6.2 店内注文の流れ <a class="header-anchor" href="#_6-2-店内注文の流れ" aria-label="Permalink to &quot;6.2 店内注文の流れ&quot;">​</a></h2><h3 id="ステップ1-テーブルを選択する" tabindex="-1">ステップ1：テーブルを選択する <a class="header-anchor" href="#ステップ1-テーブルを選択する" aria-label="Permalink to &quot;ステップ1：テーブルを選択する&quot;">​</a></h3><ol><li>「店内注文」タブが選択されていることを確認します</li><li>画面上部の<strong>テーブル選択ドロップダウン</strong>からテーブルを選びます <ul><li>表示形式：「A-1 (4名)」（テーブルコード + 座席数）</li><li>テーブルは「テーブル管理」で登録されたものが表示されます</li></ul></li></ol><h3 id="ステップ2-カテゴリを選択する" tabindex="-1">ステップ2：カテゴリを選択する <a class="header-anchor" href="#ステップ2-カテゴリを選択する" aria-label="Permalink to &quot;ステップ2：カテゴリを選択する&quot;">​</a></h3><p>テーブル選択の下に、メニューカテゴリのタブが横スクロールで表示されます。</p><ul><li>タップするとそのカテゴリのメニューが表示されます</li><li>選択中のカテゴリは青色（#536dfe）でハイライトされます</li></ul><h3 id="ステップ3-メニューを選択する" tabindex="-1">ステップ3：メニューを選択する <a class="header-anchor" href="#ステップ3-メニューを選択する" aria-label="Permalink to &quot;ステップ3：メニューを選択する&quot;">​</a></h3><p>カテゴリタブの下に、メニュー品目がグリッド形式で表示されます。</p><p><strong>レスポンシブレイアウト：</strong></p><ul><li>スマートフォン（600px未満）：2列</li><li>タブレット（600〜900px）：3列</li><li>PC（900px以上）：4列</li></ul><p><strong>メニューカードの表示内容：</strong></p><table tabindex="0"><thead><tr><th>要素</th><th>説明</th></tr></thead><tbody><tr><td>画像</td><td>メニュー画像（高さ80px）</td></tr><tr><td>品名</td><td>メニュー名。オプションがある場合はアイコン付き</td></tr><tr><td>価格</td><td>緑色テキスト（#4caf50）で表示</td></tr><tr><td>限定バッジ</td><td>限定メニューの場合、ピンク色の「limited」バッジ</td></tr><tr><td>カート数量</td><td>カートに入っている場合、右上に数量が丸で表示</td></tr><tr><td>品切れ</td><td>品切れの場合、半透明（opacity 0.4）になり「品切れ」オーバーレイ表示</td></tr></tbody></table><h3 id="ステップ4-オプションを選択する-該当品目のみ" tabindex="-1">ステップ4：オプションを選択する（該当品目のみ） <a class="header-anchor" href="#ステップ4-オプションを選択する-該当品目のみ" aria-label="Permalink to &quot;ステップ4：オプションを選択する（該当品目のみ）&quot;">​</a></h3><p>オプショングループが設定されているメニューをタップすると、オプション選択モーダルが開きます。</p><p><strong>モーダルの構成：</strong></p><ol><li><strong>ヘッダー：</strong> メニュー名 + 閉じるボタン（×）</li><li><strong>本体：</strong> オプショングループごとにセクションが表示されます</li></ol><table tabindex="0"><thead><tr><th>要素</th><th>説明</th></tr></thead><tbody><tr><td>グループ名</td><td>オプショングループ名</td></tr><tr><td>必須バッジ</td><td>必須グループには赤色「必須」バッジ</td></tr><tr><td>任意バッジ</td><td>任意グループには灰色「任意」バッジ</td></tr><tr><td>選択肢</td><td>ラジオボタン形式。選択肢名 + 追加料金（+¥200 等）</td></tr></tbody></table><ol start="3"><li><strong>フッター：</strong> 合計金額表示 + 「カートに追加」ボタン</li></ol><p><strong>バリデーション：</strong></p><ul><li>必須グループで何も選択していない場合、「カートに追加」ボタンは無効化（グレーアウト）されます</li><li>価格は基本価格 + 選択した全オプションの追加料金で自動計算されます</li></ul><p><strong>オプション選択のない品目の場合：</strong> タップするだけでカートに追加されます（数量1）。既にカートにある場合は数量が1増えます。</p><h3 id="ステップ5-カートを確認する" tabindex="-1">ステップ5：カートを確認する <a class="header-anchor" href="#ステップ5-カートを確認する" aria-label="Permalink to &quot;ステップ5：カートを確認する&quot;">​</a></h3><p>画面下部に固定表示される<strong>カートバー</strong>でカートの内容を確認できます。</p><p><strong>カートバー（折りたたみ時）：</strong></p><ul><li>「カート (Nアイテム)」バッジ</li><li>合計金額（「¥XXXX」）</li><li>「注文送信」ボタン</li></ul><p><strong>カートバー（展開時）：</strong> カートバーのサマリー部分をタップすると展開されます。</p><table tabindex="0"><thead><tr><th>要素</th><th>説明</th></tr></thead><tbody><tr><td>品目一覧</td><td>品名（省略表示）、価格、オプション（オレンジ色小文字）</td></tr><tr><td>数量操作</td><td>各品目に [-] [数量] [+] ボタン</td></tr><tr><td>メモ欄</td><td>テキスト入力（最大200文字、プレースホルダー「ネギ抜き等」）</td></tr><tr><td>カートクリア</td><td>カートを全て空にするボタン</td></tr><tr><td>合計金額</td><td>—</td></tr><tr><td>注文送信ボタン</td><td>—</td></tr></tbody></table><p><strong>数量の操作：</strong></p><ul><li>[+] で数量を1増やす</li><li>[-] で数量を1減らす</li><li>数量が1の状態で [-] を押すと、その品目がカートから削除されます</li></ul><p><strong>同一品目・異なるオプションの扱い：</strong> 同じメニューでもオプションの組み合わせが異なれば、別の品目としてカートに追加されます。例えば「ラーメン（にんにく多め）」と「ラーメン（にんにくなし）」は別のカート行になります。</p><h3 id="ステップ6-注文を送信する" tabindex="-1">ステップ6：注文を送信する <a class="header-anchor" href="#ステップ6-注文を送信する" aria-label="Permalink to &quot;ステップ6：注文を送信する&quot;">​</a></h3><ol><li>カートの内容を確認します</li><li>「注文送信」ボタンをタップします</li><li>成功すると「注文を送信しました (¥XXXX)」トーストが表示されます</li><li>カートが自動的にクリアされます</li><li>メニューの表示が更新されます</li></ol><p><strong>送信前のバリデーション：</strong></p><ul><li>カートが空の場合：送信できません（「カートが空です」エラー）</li><li>テーブルが未選択の場合：「テーブルを選択してください」エラー</li></ul><p><strong>送信されるデータ：</strong></p><table tabindex="0"><thead><tr><th>フィールド</th><th>値</th></tr></thead><tbody><tr><td>store_id</td><td>現在の店舗ID</td></tr><tr><td>table_id</td><td>選択中のテーブルID</td></tr><tr><td>items</td><td>品目リスト（品目ID、品名、価格、数量、オプション）</td></tr><tr><td>order_type</td><td>&quot;handy&quot;</td></tr><tr><td>memo</td><td>メモ欄の内容（空でもOK）</td></tr></tbody></table><p><strong>注文送信後：</strong></p><ul><li>注文はKDS（キッチンディスプレイ）にリアルタイムで表示されます</li><li>注文ステータスは「pending」（受付）で作成されます</li><li>スタッフIDが注文に記録されます（誰が注文を入力したか追跡可能）</li></ul><hr><h2 id="_6-3-テイクアウト注文の流れ" tabindex="-1">6.3 テイクアウト注文の流れ <a class="header-anchor" href="#_6-3-テイクアウト注文の流れ" aria-label="Permalink to &quot;6.3 テイクアウト注文の流れ&quot;">​</a></h2><h3 id="入力フィールド" tabindex="-1">入力フィールド <a class="header-anchor" href="#入力フィールド" aria-label="Permalink to &quot;入力フィールド&quot;">​</a></h3><p>「テイクアウト」タブを選択すると、テーブル選択の代わりに以下のフィールドが表示されます。</p><table tabindex="0"><thead><tr><th>フィールド</th><th>種類</th><th>必須</th><th>説明</th></tr></thead><tbody><tr><td>お客さん名</td><td>テキスト</td><td>✅</td><td>受取人の名前</td></tr><tr><td>電話番号</td><td>電話番号</td><td>✅</td><td>連絡先電話番号</td></tr><tr><td>受取時間</td><td>日時選択</td><td>✅</td><td>受取日時（初期値は現在時刻）</td></tr></tbody></table><h3 id="注文の流れ" tabindex="-1">注文の流れ <a class="header-anchor" href="#注文の流れ" aria-label="Permalink to &quot;注文の流れ&quot;">​</a></h3><p>メニュー選択・オプション選択・カート操作は店内注文と同じです。</p><p><strong>送信されるデータ（店内注文との違い）：</strong></p><table tabindex="0"><thead><tr><th>フィールド</th><th>値</th></tr></thead><tbody><tr><td>store_id</td><td>現在の店舗ID</td></tr><tr><td>items</td><td>品目リスト</td></tr><tr><td>order_type</td><td>&quot;takeout&quot;</td></tr><tr><td>customer_name</td><td>お客さん名</td></tr><tr><td>customer_phone</td><td>電話番号</td></tr><tr><td>pickup_at</td><td>受取日時（MySQL形式：YYYY-MM-DD HH:mm:ss）</td></tr><tr><td>memo</td><td>メモ欄の内容</td></tr></tbody></table><p><strong>テイクアウト注文のバリデーション：</strong></p><ul><li>お客さん名が空：送信できません</li><li>電話番号が空：送信できません</li><li>受取時間が未設定：「受取時間を入力してください」エラー</li></ul><hr><h2 id="_6-4-テーブル状況タブ" tabindex="-1">6.4 テーブル状況タブ <a class="header-anchor" href="#_6-4-テーブル状況タブ" aria-label="Permalink to &quot;6.4 テーブル状況タブ&quot;">​</a></h2><p>「テーブル状況」タブでは、全テーブルの現在の状態をカード形式で確認できます。フロアマップと同様のデータを使用しますが、ハンディPOS画面に最適化されたレイアウトです。</p><h3 id="テーブルカードの表示" tabindex="-1">テーブルカードの表示 <a class="header-anchor" href="#テーブルカードの表示" aria-label="Permalink to &quot;テーブルカードの表示&quot;">​</a></h3><table tabindex="0"><thead><tr><th>ステータス</th><th>バッジ</th><th>色</th></tr></thead><tbody><tr><td>空席</td><td>空席</td><td>グレー</td></tr><tr><td>未注文</td><td>未注文</td><td>黄色</td></tr><tr><td>食事中</td><td>食事中</td><td>緑色</td></tr><tr><td>会計待ち</td><td>会計待ち</td><td>赤色</td></tr><tr><td>超過中</td><td>超過中</td><td>赤色（時間超過）</td></tr></tbody></table><p><strong>カードの表示内容：</strong></p><ul><li>テーブルコード</li><li>ステータスバッジ</li><li>ゲスト数（セッションがある場合）</li><li>経過時間（セッションがある場合）</li><li>残り時間（食べ放題プランがある場合）</li><li>プラン/コース情報</li><li>注文金額合計</li><li>調理進捗バー（品目のステータス割合）</li><li>メモ（設定されている場合は黄色ボックス）</li></ul><h3 id="着席操作" tabindex="-1">着席操作 <a class="header-anchor" href="#着席操作" aria-label="Permalink to &quot;着席操作&quot;">​</a></h3><p>空きテーブルの「着席」ボタンをタップすると、着席モーダルが開きます。</p><p><strong>モーダルのフィールド：</strong></p><table tabindex="0"><thead><tr><th>フィールド</th><th>種類</th><th>必須</th><th>初期値</th><th>説明</th></tr></thead><tbody><tr><td>人数</td><td>数値入力</td><td>—</td><td>2</td><td>最小値1</td></tr><tr><td>食べ放題プラン</td><td>ドロップダウン</td><td>—</td><td>プランなし（通常）</td><td>登録済みプラン一覧。表示形式：「プラン名 (60分 ¥2,980)」</td></tr><tr><td>コース</td><td>ドロップダウン</td><td>—</td><td>コースなし（通常）</td><td>登録済みコース一覧。表示形式：「コース名 (¥5,000)」</td></tr><tr><td>メモ</td><td>テキストエリア（2行）</td><td>—</td><td>—</td><td>プレースホルダー「アレルギー・VIP等」</td></tr></tbody></table><p><strong>注意：</strong> 食べ放題プランとコースは排他的です。両方同時には選択できません。</p><p>「着席する」ボタンをタップするとセッションが開始されます。</p><h3 id="メモ編集" tabindex="-1">メモ編集 <a class="header-anchor" href="#メモ編集" aria-label="Permalink to &quot;メモ編集&quot;">​</a></h3><p>使用中テーブルの「メモ編集」ボタンをタップすると、メモモーダルが開きます。フロアマップのメモ機能と同じプリセットタグ（アレルギー注意、VIP、お子様連れ、誕生日、接待、車椅子）とテキストエリアが利用できます。</p><h3 id="着席キャンセル" tabindex="-1">着席キャンセル <a class="header-anchor" href="#着席キャンセル" aria-label="Permalink to &quot;着席キャンセル&quot;">​</a></h3><p>使用中テーブルの「着席キャンセル」ボタンをタップすると、セッションが強制終了されます。未会計の注文は全てキャンセルされ、セッショントークンが再生成されます。</p><hr><h2 id="_6-5-注文履歴タブ" tabindex="-1">6.5 注文履歴タブ <a class="header-anchor" href="#_6-5-注文履歴タブ" aria-label="Permalink to &quot;6.5 注文履歴タブ&quot;">​</a></h2><p>「注文履歴」タブでは、当日の全注文を一覧で確認・編集できます。</p><h3 id="注文カードの表示" tabindex="-1">注文カードの表示 <a class="header-anchor" href="#注文カードの表示" aria-label="Permalink to &quot;注文カードの表示&quot;">​</a></h3><p>各注文はカード形式で表示されます。</p><table tabindex="0"><thead><tr><th>要素</th><th>説明</th></tr></thead><tbody><tr><td>左ボーダー色</td><td>店内注文：青色（#536dfe）、テイクアウト：オレンジ色（#ff6f00）</td></tr><tr><td>ヘッダー</td><td>「テーブルA-1」または「TO: 顧客名」</td></tr><tr><td>時刻</td><td>注文時刻（「14:30」）</td></tr><tr><td>ステータスバッジ</td><td>色分けされたステータス（下表参照）</td></tr><tr><td>品目一覧</td><td>「2x ハンバーグ (+チーズ)」「1x ポテト」形式</td></tr><tr><td>合計金額</td><td>緑色で表示（「¥1,960」）</td></tr><tr><td>編集ボタン</td><td>「編集」（未会計の注文のみ）</td></tr></tbody></table><h3 id="注文ステータスの色分け" tabindex="-1">注文ステータスの色分け <a class="header-anchor" href="#注文ステータスの色分け" aria-label="Permalink to &quot;注文ステータスの色分け&quot;">​</a></h3><table tabindex="0"><thead><tr><th>ステータス</th><th>アイコン</th><th>背景色</th></tr></thead><tbody><tr><td>pending（受付）</td><td>⏳</td><td>オレンジ（#e65100）</td></tr><tr><td>preparing（調理中）</td><td>👨‍🍳</td><td>黄色（#f9a825）</td></tr><tr><td>ready（完成）</td><td>✅</td><td>緑色（#2e7d32）</td></tr><tr><td>served（提供済）</td><td>🍽️</td><td>グレー（#455a64）</td></tr><tr><td>cancelled（キャンセル）</td><td>❌</td><td>赤色（#c62828）、取り消し線</td></tr></tbody></table><h3 id="注文の編集" tabindex="-1">注文の編集 <a class="header-anchor" href="#注文の編集" aria-label="Permalink to &quot;注文の編集&quot;">​</a></h3><p>会計済み（paid）またはキャンセル済み（cancelled）でない注文は編集できます。</p><ol><li>注文カードの「編集」ボタンをタップします</li><li>画面上部にオレンジ色のバナーが表示されます：「修正中: [テーブルコード or 顧客名]」</li><li>注文の品目がカートに読み込まれます</li><li>注文タイプに応じたタブ（店内注文/テイクアウト）に自動切替されます</li><li>カートの内容を変更します（品目の追加・削除・数量変更）</li><li>「注文送信」ボタン（オレンジ色に変化）をタップして更新を送信します</li><li>成功すると注文が更新されます</li></ol><p><strong>編集のキャンセル：</strong> バナーの「キャンセル」ボタンをタップすると、編集モードを終了し、カートがクリアされます。</p><hr><h2 id="_6-6-スタッフ呼び出しアラート" tabindex="-1">6.6 スタッフ呼び出しアラート <a class="header-anchor" href="#_6-6-スタッフ呼び出しアラート" aria-label="Permalink to &quot;6.6 スタッフ呼び出しアラート&quot;">​</a></h2><p>ハンディPOS画面では、お客さんからのスタッフ呼び出しアラートがリアルタイムで表示されます。5秒ごとに自動チェックされます。</p><h3 id="アラートの種類" tabindex="-1">アラートの種類 <a class="header-anchor" href="#アラートの種類" aria-label="Permalink to &quot;アラートの種類&quot;">​</a></h3><table tabindex="0"><thead><tr><th>種類</th><th>アイコン</th><th>表示内容</th><th>対応ボタン</th></tr></thead><tbody><tr><td>staff_call（スタッフ呼び出し）</td><td>🔔</td><td>「テーブルA-1 呼び出し：「お水ください」」</td><td>「対応済み」</td></tr><tr><td>product_ready（料理完成通知）</td><td>🍳</td><td>「テーブルA-1 パスタ」</td><td>「配膳完了」</td></tr><tr><td>kitchen_call（キッチンからの連絡）</td><td>👨‍🍳</td><td>アラート理由（例：「塩辛すぎた」）</td><td>「対応済み」</td></tr></tbody></table><h3 id="アラートの表示" tabindex="-1">アラートの表示 <a class="header-anchor" href="#アラートの表示" aria-label="Permalink to &quot;アラートの表示&quot;">​</a></h3><ul><li>ヘッダーの下に赤色バナーとして表示されます</li><li>経過時間が表示されます（「5秒前」「2分前」）</li><li>種類に応じた効果音が鳴ります <ul><li>staff_call：高周波ビープ音</li><li>product_ready：低〜中周波ビープ音</li><li>kitchen_call：高〜中〜高の3連ビープ音（×2セット）</li></ul></li></ul><h3 id="アラートの対応" tabindex="-1">アラートの対応 <a class="header-anchor" href="#アラートの対応" aria-label="Permalink to &quot;アラートの対応&quot;">​</a></h3><ol><li>アラートの「対応済み」（または「配膳完了」）ボタンをタップします</li><li>アラートが消えます（ステータスが「acknowledged」に更新されます）</li></ol><hr><h2 id="_6-7-メニューの自動更新" tabindex="-1">6.7 メニューの自動更新 <a class="header-anchor" href="#_6-7-メニューの自動更新" aria-label="Permalink to &quot;6.7 メニューの自動更新&quot;">​</a></h2><p>ハンディPOS画面では、メニューの変更を自動的に検知します。</p><ul><li><strong>3分ごと</strong>にメニューバージョンをチェックします</li><li>管理ダッシュボードでメニューが変更された場合、次のバージョンチェックでメニューが自動更新されます</li><li>手動リフレッシュは不要です</li><li>更新はバックグラウンドで行われ、現在のカートの内容には影響しません</li></ul><hr><h2 id="_6-8-品切れ品目の扱い" tabindex="-1">6.8 品切れ品目の扱い <a class="header-anchor" href="#_6-8-品切れ品目の扱い" aria-label="Permalink to &quot;6.8 品切れ品目の扱い&quot;">​</a></h2><p>品切れに設定されたメニューは以下のように表示されます。</p><ul><li>メニューカードが半透明（opacity 0.4）になります</li><li>「品切れ」テキストがオーバーレイ表示されます</li><li>タップしてもカートに追加できません</li></ul><p><strong>注文送信時の品切れチェック：</strong> 注文送信時にサーバー側で品切れチェックが行われます。カートに入れた後にメニューが品切れになった場合、送信時にエラーが返されます。</p><ul><li>HTTPステータス409</li><li>エラーメッセージ：「品切れの品目が含まれています: [品目名]」</li></ul><p>この場合、該当品目をカートから削除して再送信してください。</p>',110)])])}const c=d(e,[["render",i]]);export{u as __pageData,c as default};
